using System.Text; using Microsoft.AspNetCore.Authentication.JwtBearer; using Microsoft.IdentityModel.Tokens; using ValoraPesquisa.Api.Middleware; using ValoraPesquisa.Application.Contracts; using ValoraPesquisa.Application.Services; using ValoraPesquisa.Infrastructure.Database; using ValoraPesquisa.Infrastructure.Repositories; using ValoraPesquisa.Infrastructure.Security;
var builder=WebApplication.CreateBuilder(args); builder.Services.AddControllers(); builder.Services.AddHttpContextAccessor(); builder.Services.AddSingleton<IConfigurationLike>(_=>new DbConfig(builder.Configuration.GetConnectionString("Postgres")??"Host=localhost;Database=valorapesquisa;Username=postgres;Password=postgres")); builder.Services.AddScoped<PostgresConnectionFactory>(); builder.Services.AddScoped<IPasswordHasher,BCryptPasswordHasher>(); builder.Services.AddScoped<ITokenHasher,Sha256TokenHasher>(); builder.Services.AddScoped<IAuditService,AuditService>(); builder.Services.AddScoped<IUserRepository,UserRepository>(); builder.Services.AddScoped<IOrganizationRepository,OrganizationRepository>(); builder.Services.AddScoped<IFormRepository,FormRepository>(); builder.Services.AddScoped<ISurveyRepository,SurveyRepository>(); builder.Services.AddScoped<ISurveyLinkRepository,SurveyLinkRepository>(); builder.Services.AddScoped<IResponseRepository,ResponseRepository>(); builder.Services.AddScoped<QuestionScoreCalculator>(); builder.Services.AddScoped<SurveyResultCalculator>();
var key=Encoding.UTF8.GetBytes(builder.Configuration["Jwt:Key"]??"dev-only-change-this-key-with-32-chars"); builder.Services.AddAuthentication(JwtBearerDefaults.AuthenticationScheme).AddJwtBearer(o=>o.TokenValidationParameters=new(){ValidateIssuer=false,ValidateAudience=false,IssuerSigningKey=new SymmetricSecurityKey(key),ValidateIssuerSigningKey=true}); builder.Services.AddAuthorization();
var app=builder.Build(); app.UseMiddleware<CorrelationIdMiddleware>(); app.UseMiddleware<ErrorHandlingMiddleware>(); app.UseAuthentication(); app.UseAuthorization(); app.MapControllers(); app.Run();
public record DbConfig(string ConnectionString):IConfigurationLike;
public partial class Program {}
